WHERE supermercado = 'saojorge'
  AND run_id IN ('curadoria-sacolao-sao-jorge-abre-mes-2026-04-u1', 'curadoria-sacolao-sao-jorge-abre-mes-2026-04-u2', 'curadoria-sacolao-sao-jorge-abre-mes-2026-04-u3', 'curadoria-sacolao-sao-jorge-abre-mes-2026-04');


